import Link from "next/link";
import { prisma } from "@/lib/prisma";
import { AdminEntryGate } from "./AdminEntryGate";

export const dynamic = "force-dynamic";

export default async function BlogPage() {
  const posts = await prisma.blogPost
    .findMany({
      where: { status: "published" },
      orderBy: { published_at: "desc" },
    })
    .catch(() => []);

  return (
    <main>
      <h1>Blog</h1>
      <p>Published posts from the database.</p>
      <AdminEntryGate />
      <div className="grid">
        {posts.map((post) => (
          <article key={post.id} className="card">
            <h2>{post.title}</h2>
            <p>{post.excerpt}</p>
            <p>
              <strong>Author:</strong> {post.author}
            </p>
            <p>
              <strong>Published:</strong> {post.published_at.toISOString().slice(0, 10)}
            </p>
            <p>
              <strong>Read time:</strong> {post.reading_minutes} minutes
            </p>
            <p>
              <Link href={`/api/blog/posts/${post.slug}`}>Open JSON detail</Link>
            </p>
          </article>
        ))}
        {posts.length === 0 ? (
          <p className="card">No published posts yet.</p>
        ) : null}
      </div>
    </main>
  );
}
